+const tempRoots: string[] = [];
+
+async function createTempAvatarRoot() {
+  const root = await fs.mkdtemp(path.join(os.tmpdir(), "openclaw-avatar-"));
+  tempRoots.push(root);
+  return root;
+}
+
+afterEach(async () => {
+  await Promise.all(
+    tempRoots
+      .splice(0, tempRoots.length)
+      .map((root) => fs.rm(root, { recursive: true, force: true })),
+  );
+});
